import sys

def main():
    import sys
    input = sys.stdin.read
    N, M, K = map(int, input().split())

    # Ensure N < M for easier calculation
    if N > M:
        N, M = M, N

    # Count numbers <= x divisible by exactly one of N or M
    def count(x):
        cnt_n = x // N
        cnt_m = x // M
        cnt_both = x // (N * M // gcd(N, M))
        return cnt_n + cnt_m - 2 * cnt_both

    # Binary search for the K-th number
    low = 1
    high = 10**18  # A sufficiently large upper bound

    while low < high:
        mid = (low + high) // 2
        if count(mid) < K:
            low = mid + 1
        else:
            high = mid

    print(low)

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

if __name__ == "__main__":
    main()
